import {
  DIGITAL_CONCIERGE_ACCEPT_ANY,
  DIGITAL_CONCIERGE_DEFAULT_PLATFORM,
  DIGITAL_CONCIERGE_HEADER_ACCEPT,
  DIGITAL_CONCIERGE_HEADER_PLATFORM,
  HEADER_CONTENT_TYPE,
  JSON_CONTENT_TYPE
} from "../../util/endpointConstants.js";
import type { Logger } from "../../util/logger.js";
import { ContentstackRegion } from "../../util/regions.js";
import { randomUid } from "../../util/uid.js";

import {
  DIGITAL_CONCIERGE_HEADER_LIMIT,
  DIGITAL_CONCIERGE_HEADER_SESSION_ID,
  resolveDigitalConciergeSearchUrl
} from "./searchEndpoints.js";
import {
  isConciergeSearchHit
} from "./searchTypes.js";
import type {
  ConciergeSearchConfig,
  ConciergeSearchHit,
  ConciergeSearchInput,
  ConciergeSearchMetadataField,
  ConciergeSearchResult,
  ConciergeSearchResultItem
} from "./searchTypes.js";
import type { ConciergeSource } from "./types.js";

const VALID_REGIONS = new Set(Object.values(ContentstackRegion) as string[]);

function validateConfig(config: ConciergeSearchConfig): void {
  if (!config.apiKey || typeof config.apiKey !== "string" || !config.apiKey.trim()) {
    throw new Error("ConciergeSearch: apiKey is required and must be a non-empty string");
  }

  const raw = config as unknown as Record<string, unknown>;
  const hasRegion = "region" in raw && raw.region !== undefined;
  const hasEndpoint = "endpoint" in raw && raw.endpoint !== undefined;

  if (!hasRegion && !hasEndpoint) {
    throw new Error("ConciergeSearch: either region or endpoint must be provided");
  }
  if (hasRegion && hasEndpoint) {
    throw new Error("ConciergeSearch: region and endpoint are mutually exclusive — provide one, not both");
  }
  if (hasRegion && !VALID_REGIONS.has(raw.region as string)) {
    throw new Error(`ConciergeSearch: invalid region "${raw.region as string}". Valid regions: ${Array.from(VALID_REGIONS).join(", ")}`);
  }
  if (hasEndpoint && (typeof raw.endpoint !== "string" || !raw.endpoint.trim())) {
    throw new Error("ConciergeSearch: endpoint must be a non-empty string");
  }
}

function isSearchMetadataField(value: unknown): value is ConciergeSearchMetadataField {
  if (!value || typeof value !== "object") return false;
  const v = value as Record<string, unknown>;
  const valueType = typeof v.value;
  return (valueType === "string" || valueType === "number") && typeof v.isSource === "boolean";
}

function normalizeMetadata(raw: unknown): Record<string, ConciergeSearchMetadataField> {
  const out: Record<string, ConciergeSearchMetadataField> = {};
  if (!raw || typeof raw !== "object") return out;
  for (const [key, value] of Object.entries(raw as Record<string, unknown>)) {
    if (!isSearchMetadataField(value)) continue;
    const field: ConciergeSearchMetadataField = { value: value.value, isSource: value.isSource };
    if (typeof (value as { type?: unknown }).type === "string") {
      field.type = (value as { type: string }).type;
    }
    out[key] = field;
  }
  return out;
}

function normalizeHit(obj: Record<string, unknown>): ConciergeSearchHit | null {
  if (typeof obj.uid !== "string" || typeof obj.project_uid !== "string") return null;
  return {
    uid: obj.uid,
    project_uid: obj.project_uid,
    metadata: normalizeMetadata(obj.metadata)
  };
}

function normalizeResults(raw: unknown): ConciergeSearchResultItem[] {
  if (!Array.isArray(raw)) return [];
  const items: ConciergeSearchResultItem[] = [];
  for (const r of raw) {
    if (!r || typeof r !== "object") continue;
    const obj = r as Record<string, unknown>;

    const hit = normalizeHit(obj);
    if (hit) {
      items.push(hit);
      continue;
    }

    if (typeof obj.content_uid === "string") {
      items.push({ content_uid: obj.content_uid });
      continue;
    }
  }
  return items;
}

function extractSources(items: ConciergeSearchResultItem[]): ConciergeSource[] {
  const map = new Map<string, ConciergeSource>();
  for (const item of items) {
    if (!isConciergeSearchHit(item)) continue;
    for (const [key, field] of Object.entries(item.metadata)) {
      if (!field.isSource) continue;
      if (typeof field.value !== "string") continue;
      const source: ConciergeSource = field.type
        ? { key, value: field.value, contentType: field.type }
        : { key, value: field.value };
      map.set(`${key}:${field.value}`, source);
    }
  }
  return Array.from(map.values());
}

export class ConciergeSearch {
  private readonly config: ConciergeSearchConfig;
  private readonly logger: Logger;
  private readonly platform: string;
  private currentSessionId: string;
  private lastQuery: string | null = null;

  constructor(config: ConciergeSearchConfig) {
    validateConfig(config);
    this.config = config;
    this.logger = config.logger ?? {};
    this.platform = config.platform ?? DIGITAL_CONCIERGE_DEFAULT_PLATFORM;
    this.currentSessionId = config.sessionId ?? randomUid();
  }

  setSessionId(sessionId: string): this {
    if (!sessionId || typeof sessionId !== "string" || !sessionId.trim()) {
      throw new Error("ConciergeSearch: sessionId must be a non-empty string");
    }
    this.currentSessionId = sessionId;
    this.lastQuery = null;
    return this;
  }

  getSessionId(): string {
    return this.currentSessionId;
  }

  clearSession(): void {
    this.currentSessionId = randomUid();
    this.lastQuery = null;
  }

  async search(input: ConciergeSearchInput): Promise<ConciergeSearchResult> {
    if (!input.query.trim()) {
      throw new Error("ConciergeSearch: query is required and must be a non-empty string");
    }

    const trimmedQuery = input.query.trim();
    const perCallSession =
      typeof input.sessionId === "string" && input.sessionId.trim().length > 0
        ? input.sessionId
        : null;

    let sessionId: string;
    let omitQueryInBody: boolean;

    if (perCallSession !== null) {
      sessionId = perCallSession;
      omitQueryInBody = false;
    } else {
      if (this.lastQuery !== null && this.lastQuery !== trimmedQuery) {
        this.currentSessionId = randomUid();
      }
      sessionId = this.currentSessionId;
      omitQueryInBody = this.lastQuery === trimmedQuery;
      this.lastQuery = trimmedQuery;
    }

    const limit = input.limit ?? this.config.defaultLimit;

    const cfgRaw = this.config as unknown as Record<string, unknown>;
    const url = resolveDigitalConciergeSearchUrl({
      apiKey: this.config.apiKey,
      ...("region" in cfgRaw && cfgRaw.region ? { region: cfgRaw.region as ContentstackRegion } : {}),
      ...("endpoint" in cfgRaw && cfgRaw.endpoint ? { endpoint: cfgRaw.endpoint as string } : {})
    });

    const headers: Record<string, string> = {
      [DIGITAL_CONCIERGE_HEADER_ACCEPT]: DIGITAL_CONCIERGE_ACCEPT_ANY,
      [HEADER_CONTENT_TYPE]: JSON_CONTENT_TYPE,
      [DIGITAL_CONCIERGE_HEADER_PLATFORM]: this.platform,
      [DIGITAL_CONCIERGE_HEADER_SESSION_ID]: sessionId
    };
    if (typeof limit === "number" && Number.isFinite(limit) && limit > 0) {
      headers[DIGITAL_CONCIERGE_HEADER_LIMIT] = String(Math.floor(limit));
    }

    this.logger.debug?.("digitalConcierge.search.request", { url, sessionId, limit });
    this.logger.log?.("debug", "digitalConcierge.search.request", { url, sessionId, limit });

    const res = await fetch(url, {
      method: "POST",
      headers,
      body: JSON.stringify(omitQueryInBody ? {} : { query: trimmedQuery }),
      ...(input.signal ? { signal: input.signal } : {})
    });

    if (!res.ok) {
      const text = await res.text().catch(() => "");
      throw new Error(`Digital Concierge search failed: ${String(res.status)} ${res.statusText} ${text}`);
    }

    const raw: unknown = await res.json();
    const rawResults = raw && typeof raw === "object" ? (raw as Record<string, unknown>).results : undefined;
    const results = normalizeResults(rawResults);
    const sources = extractSources(results);

    return { sessionId, results, sources, raw };
  }
}
