import {
  addPersistedThreadId,
  appendThreadMessage,
  clearPersistedAll,
  clearPersistedThread,
  getPersistedCurrentThreadId,
  getPersistedUserId,
  getThreadMessages,
  resolvePersistThreadMessages,
  setPersistedCurrentThreadId,
  setPersistedUserId,
  type PersistThreadMessagesResolved
} from "../../persistence/threadMessages.js";
import {
  DIGITAL_CONCIERGE_ACCEPT_ANY,
  DIGITAL_CONCIERGE_DEFAULT_PLATFORM,
  DIGITAL_CONCIERGE_HEADER_ACCEPT,
  DIGITAL_CONCIERGE_HEADER_PLATFORM,
  DIGITAL_CONCIERGE_HEADER_USER_ID,
  DIGITAL_CONCIERGE_LOG_REQUEST,
  DIGITAL_CONCIERGE_SSE_EVENT_CHUNK_TEXT,
  DIGITAL_CONCIERGE_SSE_EVENT_METADATA,
  DIGITAL_CONCIERGE_SSE_EVENT_TOOL_RESULT,
  HEADER_CONTENT_TYPE,
  JSON_CONTENT_TYPE
} from "../../util/endpointConstants.js";
import type { Logger } from "../../util/logger.js";
import { ContentstackRegion } from "../../util/regions.js";
import { randomUid } from "../../util/uid.js";

import { ConversationStore } from "./conversationStore.js";
import { resolveDigitalConciergeExecuteUrl } from "./endpoints.js";
import { parseSseDataJson } from "./sseParser.js";
import type {
  ConciergeAgentConfig,
  ConciergeMetadataResult,
  ConciergeResult,
  ConciergeSource,
  ConciergeStreamEvent,
  ConciergeStreamRun,
  ConciergeTextInput
} from "./types.js";

type DcRole = "user" | "assistant";
interface DcContentItem {
  type: "text";
  text: string;
}
interface DcMessage {
  role: DcRole;
  content: DcContentItem[];
}

interface Emitter<T> {
  emit: (item: T) => void;
  end: () => void;
  iterable: AsyncIterable<T>;
}

function createEmitter<T>(): Emitter<T> {
  const buffer: T[] = [];
  let isEnded = false;
  let notify: (() => void) | null = null;

  const iterable: AsyncIterable<T> = {
    async *[Symbol.asyncIterator]() {
      for (;;) {
        if (buffer.length > 0) {
          yield buffer.shift() as T;
          continue;
        }
        if (isEnded) return;
        await new Promise<void>((r) => {
          notify = r;
        });
      }
    }
  };

  return {
    emit: (item) => {
      if (isEnded) return;
      buffer.push(item);
      notify?.();
      notify = null;
    },
    end: () => {
      isEnded = true;
      notify?.();
      notify = null;
    },
    iterable
  };
}

interface Deferred<T> {
  promise: Promise<T>;
  resolve: (value: T) => void;
  reject: (reason?: unknown) => void;
}

function createDeferred<T>(): Deferred<T> {
  let resolve!: (value: T) => void;
  let reject!: (reason?: unknown) => void;
  const promise = new Promise<T>((res, rej) => {
    resolve = res;
    reject = rej;
  });
  return { promise, resolve, reject };
}

function toDcMessages(
  history: { role: DcRole; text: string }[],
  prompt: string
): DcMessage[] {
  const messages: DcMessage[] = history.map((m) => ({
    role: m.role,
    content: [{ type: "text" as const, text: m.text }]
  }));

  messages.push({ role: "user", content: [{ type: "text", text: prompt }] });
  return messages;
}

function extractSourcesFromCustomRecord(
  custom: unknown,
  out: Map<string, ConciergeSource>
): void {
  if (!custom || typeof custom !== "object") return;
  for (const [key, value] of Object.entries(custom as Record<string, unknown>)) {
    if (!value || typeof value !== "object") continue;
    const v = value as Record<string, unknown>;
    if (v.isSource !== true) continue;
    if (typeof v.value !== "string") continue;
    const contentType = typeof v.type === "string" ? v.type : undefined;
    const source: ConciergeSource = contentType
      ? { key, value: v.value, contentType }
      : { key, value: v.value };
    out.set(`${key}:${v.value}`, source);
  }
}

function extractSourcesFromToolResult(result: unknown): ConciergeSource[] {
  const out = new Map<string, ConciergeSource>();

  if (result && typeof result === "object") {
    const r = result as Record<string, unknown>;

    const rootCustom = r.custom;
    if (Array.isArray(rootCustom)) {
      for (const entry of rootCustom) extractSourcesFromCustomRecord(entry, out);
    } else {
      extractSourcesFromCustomRecord(rootCustom, out);
    }

    const results = r.results;
    if (Array.isArray(results)) {
      for (const item of results) {
        if (!item || typeof item !== "object") continue;
        const metadata = (item as Record<string, unknown>).metadata;
        if (!metadata || typeof metadata !== "object") continue;
        const custom = (metadata as Record<string, unknown>).custom;
        extractSourcesFromCustomRecord(custom, out);
      }
    }
  }

  return Array.from(out.values());
}

function extractMetadataResults(results: unknown[]): ConciergeMetadataResult[] {
  const out: ConciergeMetadataResult[] = [];
  for (const r of results) {
    if (!r || typeof r !== "object") continue;
    const item = r as Record<string, unknown>;
    if (typeof item.content_uid !== "string") continue;
    const custom = item.custom as Record<string, { value: string; isSource: boolean; type?: string }> | undefined;
    out.push({ content_uid: item.content_uid, ...(custom ? { custom } : {}) });
  }
  return out;
}

function safeTextDelta(nextText: string, prevText: string): string {
  if (nextText.startsWith(prevText)) return nextText.slice(prevText.length);
  return nextText;
}

function safeCallback<A extends unknown[]>(fn: ((...args: A) => void) | undefined, ...args: A): void {
  if (!fn) return;
  try {
    fn(...args);
  } catch {
    // callbacks are fire-and-forget
  }
}

const VALID_REGIONS = new Set(Object.values(ContentstackRegion) as string[]);

function validateConfig(config: ConciergeAgentConfig): void {
  if (!config.apiKey || typeof config.apiKey !== "string" || !config.apiKey.trim()) {
    throw new Error("ConciergeAgent: apiKey is required and must be a non-empty string");
  }

  const raw = config as unknown as Record<string, unknown>;
  const hasRegion = "region" in raw && raw.region !== undefined;
  const hasEndpoint = "endpoint" in raw && raw.endpoint !== undefined;

  if (!hasRegion && !hasEndpoint) {
    throw new Error("ConciergeAgent: either region or endpoint must be provided");
  }

  if (hasRegion && hasEndpoint) {
    throw new Error("ConciergeAgent: region and endpoint are mutually exclusive — provide one, not both");
  }

  if (hasRegion && !VALID_REGIONS.has(raw.region as string)) {
    throw new Error(`ConciergeAgent: invalid region "${raw.region as string}". Valid regions: ${Array.from(VALID_REGIONS).join(", ")}`);
  }

  if (hasEndpoint && (typeof raw.endpoint !== "string" || !raw.endpoint.trim())) {
    throw new Error("ConciergeAgent: endpoint must be a non-empty string");
  }
}

export class ConciergeAgent {
  private readonly config: ConciergeAgentConfig;
  private readonly logger: Logger;
  private readonly store = new ConversationStore();
  private readonly platform: string;
  private readonly persist: PersistThreadMessagesResolved | null;

  private currentUserId?: string;
  private currentThreadId?: string;

  constructor(config: ConciergeAgentConfig) {
    validateConfig(config);
    this.config = config;
    this.logger = config.logger ?? {};
    this.platform = config.platform ?? DIGITAL_CONCIERGE_DEFAULT_PLATFORM;
    this.persist = resolvePersistThreadMessages(config.persistThreadMessages);
  }

  setUserId(userId: string): this {
    this.currentUserId = userId;
    return this;
  }

  setThreadId(threadId: string): this {
    this.currentThreadId = threadId;
    return this;
  }

  clearThread(threadId?: string): void {
    const userId = this.currentUserId;
    if (!userId) return;
    const tid = threadId ?? this.currentThreadId;
    if (!tid) return;
    this.store.clearThread(userId, tid);
    if (this.persist) clearPersistedThread(this.persist, tid);
  }

  clearAllThreads(): void {
    const userId = this.currentUserId;
    if (!userId) return;
    this.store.clearAllThreads(userId);
    if (this.persist) clearPersistedAll(this.persist);
  }

  async generateText(input: ConciergeTextInput): Promise<ConciergeResult> {
    const run = this.streamText(input);
    try {
      return await run.done;
    } finally {
      run.cancel();
    }
  }

  streamText(input: ConciergeTextInput): ConciergeStreamRun {
    const abortController = new AbortController();
    const events = createEmitter<ConciergeStreamEvent>();
    const textEmitter = createEmitter<string>();
    const doneDeferred = createDeferred<ConciergeResult>();
    const textDeferred = createDeferred<string>();
    const sourcesDeferred = createDeferred<ConciergeSource[]>();
    const metadataDeferred = createDeferred<ConciergeMetadataResult[]>();

    if (input.signal) {
      if (input.signal.aborted) {
        abortController.abort(input.signal.reason);
      } else {
        input.signal.addEventListener("abort", () => {
          abortController.abort(input.signal?.reason);
        }, { once: true });
      }
    }

    void (async () => {
      try {
        for await (const ev of this.streamTextEvents(input, abortController.signal)) {
          safeCallback(input.onChunk, ev);
          events.emit(ev);

          if (ev.type === "text") {
            textEmitter.emit(ev.textDelta);
          }

          if (ev.type === "done") {
            const result: ConciergeResult = {
              threadId: ev.threadId,
              userId: ev.userId,
              text: ev.text,
              sources: ev.sources,
              metadata: ev.metadata
            };
            textDeferred.resolve(ev.text);
            sourcesDeferred.resolve(ev.sources);
            metadataDeferred.resolve(ev.metadata);
            doneDeferred.resolve(result);
            safeCallback(input.onFinish, result);
          }
        }
      } catch (e) {
        const error = e instanceof Error ? e : new Error(String(e));
        events.emit({ type: "error", message: error.message });
        doneDeferred.reject(error);
        textDeferred.reject(error);
        sourcesDeferred.reject(error);
        metadataDeferred.reject(error);
        safeCallback(input.onError, error);
      } finally {
        events.end();
        textEmitter.end();
      }
    })();

    const toSSEResponse = (init?: ResponseInit): Response => {
      const encoder = new TextEncoder();
      const stream = new ReadableStream<Uint8Array>({
        async start(controller) {
          try {
            for await (const ev of events.iterable) {
              controller.enqueue(encoder.encode(`data: ${JSON.stringify(ev)}\n\n`));
            }
          } catch {
            // stream ended
          } finally {
            controller.close();
          }
        }
      });

      const sseHeaders = new Headers({
        "content-type": "text/event-stream; charset=utf-8",
        "cache-control": "no-cache, no-transform",
        connection: "keep-alive"
      });
      if (init?.headers) new Headers(init.headers).forEach((v, k) => { sseHeaders.set(k, v); });

      return new Response(stream, { ...init, headers: sseHeaders });
    };

    const toTextStreamResponse = (init?: ResponseInit): Response => {
      const encoder = new TextEncoder();
      const stream = new ReadableStream<Uint8Array>({
        async start(controller) {
          try {
            for await (const delta of textEmitter.iterable) {
              controller.enqueue(encoder.encode(delta));
            }
          } catch {
            // stream ended
          } finally {
            controller.close();
          }
        }
      });

      const textHeaders = new Headers({ "content-type": "text/plain; charset=utf-8" });
      if (init?.headers) new Headers(init.headers).forEach((v, k) => { textHeaders.set(k, v); });

      return new Response(stream, { ...init, headers: textHeaders });
    };

    return {
      events: events.iterable,
      textStream: textEmitter.iterable,
      text: textDeferred.promise,
      sources: sourcesDeferred.promise,
      metadata: metadataDeferred.promise,
      done: doneDeferred.promise,
      cancel: () => { abortController.abort(); },
      toSSEResponse,
      toTextStreamResponse
    };
  }

  async *streamTextEvents(input: ConciergeTextInput, signal?: AbortSignal): AsyncIterable<ConciergeStreamEvent> {
    const persist = this.persist;
    let userId = input.userId ?? this.currentUserId;
    let threadId = input.threadId ?? this.currentThreadId;
    if (persist) {
      userId ??= getPersistedUserId(persist);
      threadId ??= getPersistedCurrentThreadId(persist) ?? undefined;
    }
    userId = userId ?? randomUid();
    threadId = threadId ?? randomUid();

    this.currentUserId = userId;
    this.currentThreadId = threadId;

    if (persist) {
      setPersistedUserId(persist, userId);
      setPersistedCurrentThreadId(persist, threadId);
      addPersistedThreadId(persist, threadId);

      const persistedMessages = getThreadMessages({
        threadId,
        storageKey: persist.storageKey,
        storage: persist.storage
      });
      if (persistedMessages.length && this.store.getMessages(userId, threadId).length === 0) {
        this.store.setMessages(
          userId,
          threadId,
          persistedMessages.map((m) => ({ role: m.role, text: m.text, createdAtMs: m.ts }))
        );
      }
    }

    const historyAll = this.store.getMessages(userId, threadId);
    const maxHistory = this.config.options?.conversation?.maxHistoryMessages;
    const history =
      typeof maxHistory === "number" && maxHistory >= 0
        ? historyAll.slice(-maxHistory)
        : historyAll;

    this.store.appendMessage(userId, threadId, { role: "user", text: input.prompt });
    if (persist) appendThreadMessage(persist, threadId, { role: "user", text: input.prompt });

    const cfgRaw = this.config as unknown as Record<string, unknown>;
    const url = resolveDigitalConciergeExecuteUrl({
      apiKey: this.config.apiKey,
      ...("region" in cfgRaw && cfgRaw.region ? { region: cfgRaw.region as ContentstackRegion } : {}),
      ...("endpoint" in cfgRaw && cfgRaw.endpoint ? { endpoint: cfgRaw.endpoint as string } : {}),
      ...(this.config.environment !== undefined ? { environment: this.config.environment } : {})
    });

    const requestBody = {
      messages: toDcMessages(
        history.map((m) => ({ role: m.role, text: m.text })),
        input.prompt
      ),
      threadId
    };

    this.logger.debug?.(DIGITAL_CONCIERGE_LOG_REQUEST, { url, userId, threadId });
    this.logger.log?.("debug", DIGITAL_CONCIERGE_LOG_REQUEST, { url, userId, threadId });

    const res = await fetch(url, {
      method: "POST",
      headers: {
        [DIGITAL_CONCIERGE_HEADER_ACCEPT]: DIGITAL_CONCIERGE_ACCEPT_ANY,
        [HEADER_CONTENT_TYPE]: JSON_CONTENT_TYPE,
        [DIGITAL_CONCIERGE_HEADER_USER_ID]: userId,
        [DIGITAL_CONCIERGE_HEADER_PLATFORM]: this.platform
      },
      body: JSON.stringify(requestBody),
      ...(signal ? { signal } : {})
    });

    if (!res.ok) {
      const text = await res.text().catch(() => "");
      throw new Error(`Digital Concierge request failed: ${String(res.status)} ${res.statusText} ${text}`);
    }

    let lastText = "";
    const sourceMap = new Map<string, ConciergeSource>();
    const allMetadata: ConciergeMetadataResult[] = [];

    for await (const raw of parseSseDataJson(res)) {
      if (!raw || typeof raw !== "object") continue;
      const evt = raw as Record<string, unknown>;
      const type = evt.type;

      if (type === DIGITAL_CONCIERGE_SSE_EVENT_CHUNK_TEXT) {
        const payload = evt.payload as undefined | { text?: unknown };
        const text = typeof payload?.text === "string" ? payload.text : "";
        if (!text) continue;
        const delta = safeTextDelta(text, lastText);
        lastText = text;
        if (delta) yield { type: "text", textDelta: delta, text };
        continue;
      }

      if (type === DIGITAL_CONCIERGE_SSE_EVENT_TOOL_RESULT) {
        const payload = evt.payload as
          | undefined
          | { toolName?: unknown; toolCallId?: unknown; result?: unknown };
        const toolName = typeof payload?.toolName === "string" ? payload.toolName : "tool";
        const toolCallId = typeof payload?.toolCallId === "string" ? payload.toolCallId : undefined;
        const result = payload?.result;
        const sources = extractSourcesFromToolResult(result);
        for (const s of sources) sourceMap.set(`${s.key}:${s.value}`, s);
        yield {
          type: "toolResult",
          toolName,
          ...(toolCallId ? { toolCallId } : {}),
          result,
          sources
        };
        continue;
      }

      if (type === DIGITAL_CONCIERGE_SSE_EVENT_METADATA) {
        const rawResults = evt.results;
        if (Array.isArray(rawResults)) {
          const metadataResults = extractMetadataResults(rawResults);
          allMetadata.push(...metadataResults);
          for (const item of metadataResults) {
            if (item.custom) {
              extractSourcesFromCustomRecord(item.custom, sourceMap);
            }
          }
          const sources = Array.from(sourceMap.values());
          yield { type: "metadata", results: metadataResults, sources };
        }
        continue;
      }
    }

    if (lastText) this.store.appendMessage(userId, threadId, { role: "assistant", text: lastText });
    if (persist && lastText) appendThreadMessage(persist, threadId, { role: "assistant", text: lastText });

    const sources = Array.from(sourceMap.values());
    yield { type: "done", threadId, userId, text: lastText, sources, metadata: allMetadata };
  }
}
