import { DIGITAL_CONCIERGE_BASE_URL_BY_REGION, DIGITAL_CONCIERGE_EXECUTE_PATH_PREFIX, DIGITAL_CONCIERGE_EXECUTE_PATH_SUFFIX } from "../../util/endpointConstants.js";
import type { ContentstackRegion } from "../../util/regions.js";

export type ConciergeEnvironment = string;

export function resolveDigitalConciergeBaseUrl(
  region: ContentstackRegion,
  environment?: ConciergeEnvironment
): string {
  void environment;
  const baseUrl = DIGITAL_CONCIERGE_BASE_URL_BY_REGION[region];
  if (!baseUrl) throw new Error(`No Digital Concierge base URL configured for region=${region}`);
  return baseUrl;
}

export function resolveDigitalConciergeExecuteUrl(params: {
  apiKey: string;
  region?: ContentstackRegion;
  endpoint?: string;
  environment?: ConciergeEnvironment;
}): string {
  if (params.endpoint) {
    return `${params.endpoint}${DIGITAL_CONCIERGE_EXECUTE_PATH_PREFIX}${params.apiKey}${DIGITAL_CONCIERGE_EXECUTE_PATH_SUFFIX}`;
  }
  if (!params.region) {
    throw new Error("Either region or endpoint must be provided");
  }
  const baseUrl = resolveDigitalConciergeBaseUrl(params.region, params.environment);
  return `${baseUrl}${DIGITAL_CONCIERGE_EXECUTE_PATH_PREFIX}${params.apiKey}${DIGITAL_CONCIERGE_EXECUTE_PATH_SUFFIX}`;
}
