import { DIGITAL_CONCIERGE_BASE_URL_BY_REGION } from "../../util/endpointConstants.js";
import type { ContentstackRegion } from "../../util/regions.js";

export const DIGITAL_CONCIERGE_SEARCH_PATH_PREFIX = "/digital-concierge/";
export const DIGITAL_CONCIERGE_SEARCH_PATH_SUFFIX = "/search";

export const DIGITAL_CONCIERGE_HEADER_SESSION_ID = "x-session-id";
export const DIGITAL_CONCIERGE_HEADER_LIMIT = "x-limit";

export function resolveDigitalConciergeSearchUrl(params: {
  apiKey: string;
  region?: ContentstackRegion;
  endpoint?: string;
}): string {
  if (params.endpoint) {
    return `${params.endpoint}${DIGITAL_CONCIERGE_SEARCH_PATH_PREFIX}${params.apiKey}${DIGITAL_CONCIERGE_SEARCH_PATH_SUFFIX}`;
  }
  if (!params.region) {
    throw new Error("Either region or endpoint must be provided");
  }
  const baseUrl = DIGITAL_CONCIERGE_BASE_URL_BY_REGION[params.region];
  if (!baseUrl) throw new Error(`No Digital Concierge base URL configured for region=${params.region}`);
  return `${baseUrl}${DIGITAL_CONCIERGE_SEARCH_PATH_PREFIX}${params.apiKey}${DIGITAL_CONCIERGE_SEARCH_PATH_SUFFIX}`;
}
