export type ConversationRole = "user" | "assistant";

export interface ConversationMessage {
  role: ConversationRole;
  text: string;
  createdAtMs: number;
}

export class ConversationStore {
  private readonly byUserId = new Map<string, Map<string, ConversationMessage[]>>();

  getMessages(userId: string, threadId: string): ConversationMessage[] {
    const userThreads = this.byUserId.get(userId);
    if (!userThreads) return [];
    return userThreads.get(threadId) ?? [];
  }

  setMessages(userId: string, threadId: string, messages: ConversationMessage[]) {
    let userThreads = this.byUserId.get(userId);
    if (!userThreads) {
      userThreads = new Map();
      this.byUserId.set(userId, userThreads);
    }
    userThreads.set(threadId, messages);
  }

  appendMessage(userId: string, threadId: string, message: Omit<ConversationMessage, "createdAtMs">) {
    let userThreads = this.byUserId.get(userId);
    if (!userThreads) {
      userThreads = new Map();
      this.byUserId.set(userId, userThreads);
    }
    let messages = userThreads.get(threadId);
    if (!messages) {
      messages = [];
      userThreads.set(threadId, messages);
    }
    messages.push({ ...message, createdAtMs: Date.now() });
  }

  clearThread(userId: string, threadId: string) {
    const userThreads = this.byUserId.get(userId);
    if (!userThreads) return;
    userThreads.delete(threadId);
    if (userThreads.size === 0) this.byUserId.delete(userId);
  }

  clearAllThreads(userId: string) {
    this.byUserId.delete(userId);
  }
}

