import type { ConciergeMetadataResult, ConciergeResult, ConciergeSource, ConciergeStreamEvent, ConciergeTextInput } from "../agents/digital-concierge/types.js";

type FetchLike = typeof fetch;

interface Emitter<T> {
  emit: (item: T) => void;
  end: () => void;
  iterable: AsyncIterable<T>;
}

function createEmitter<T>(): Emitter<T> {
  const buffer: T[] = [];
  let isEnded = false;
  let notify: (() => void) | null = null;

  const iterable: AsyncIterable<T> = {
    async *[Symbol.asyncIterator]() {
      for (;;) {
        if (buffer.length > 0) {
          yield buffer.shift() as T;
          continue;
        }
        if (isEnded) return;
        await new Promise<void>((r) => {
          notify = r;
        });
      }
    }
  };

  return {
    emit: (item) => {
      if (isEnded) return;
      buffer.push(item);
      notify?.();
      notify = null;
    },
    end: () => {
      isEnded = true;
      notify?.();
      notify = null;
    },
    iterable
  };
}

function normalizeChunk(chunk: string): string {
  return chunk.replace(/\r/g, "");
}

interface Deferred<T> {
  promise: Promise<T>;
  resolve: (value: T) => void;
  reject: (reason?: unknown) => void;
}

function createDeferred<T>(): Deferred<T> {
  let resolve!: (value: T) => void;
  let reject!: (reason?: unknown) => void;
  const promise = new Promise<T>((res, rej) => {
    resolve = res;
    reject = rej;
  });
  return { promise, resolve, reject };
}

export interface ConciergeClientStreamRun {
  events: AsyncIterable<ConciergeClientEvent>;
  textStream: AsyncIterable<string>;
  done: Promise<ConciergeResult>;
  cancel: () => void;
}

export interface ConciergeClientTextEvent {
  type: "text";
  textDelta: string;
  text: string;
}

export interface ConciergeClientSourcesEvent {
  type: "sources";
  sources: ConciergeSource[];
}

export interface ConciergeClientMetadataEvent {
  type: "metadata";
  results: ConciergeMetadataResult[];
  sources: ConciergeSource[];
}

export interface ConciergeClientDoneEvent {
  type: "done";
  threadId: string;
  userId: string;
  text: string;
  sources: ConciergeSource[];
  metadata: ConciergeMetadataResult[];
}

export interface ConciergeClientErrorEvent {
  type: "error";
  message: string;
}

export type ConciergeClientEvent =
  | ConciergeClientTextEvent
  | ConciergeClientSourcesEvent
  | ConciergeClientMetadataEvent
  | ConciergeClientDoneEvent
  | ConciergeClientErrorEvent;

export interface ConciergeClient {
  streamText: (input: ConciergeTextInput) => ConciergeClientStreamRun;
  generateText: (input: ConciergeTextInput) => Promise<ConciergeResult>;
}

export function createConciergeClient(params: { endpoint: string; fetch?: FetchLike }): ConciergeClient {
  const fetchImpl = params.fetch ?? fetch;

  const streamText: ConciergeClient["streamText"] = (input) => {
    const abortController = new AbortController();
    const events = createEmitter<ConciergeClientEvent>();
    const text = createEmitter<string>();
    const done = createDeferred<ConciergeResult>();

    void (async () => {
      try {
        const res = await fetchImpl(params.endpoint, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify(input),
          signal: abortController.signal
        });

        if (!res.ok) {
          const text = await res.text().catch(() => "");
          const msg = `Request failed: ${String(res.status)} ${res.statusText}${text ? ` — ${text}` : ""}`;
          events.emit({ type: "error", message: msg });
          done.reject(new Error(msg));
          return;
        }

        const body = res.body;
        if (!body) {
          const msg = "No response body";
          events.emit({ type: "error", message: msg });
          done.reject(new Error(msg));
          return;
        }

        const reader = body.getReader();
        const decoder = new TextDecoder();
        let buffer = "";
        let sawDone = false;
        let shouldStop = false;

        for (;;) {
          if (shouldStop) break;
          const { value, done: readerDone } = await reader.read();
          if (readerDone) break;
          buffer = normalizeChunk(buffer + decoder.decode(value, { stream: true }));

          for (;;) {
            const boundary = buffer.indexOf("\n\n");
            if (boundary === -1) break;
            const rawEvent = buffer.slice(0, boundary);
            buffer = buffer.slice(boundary + 2);

            const lines = rawEvent
              .split("\n")
              .map((l) => l.trim())
              .filter(Boolean);

            for (const line of lines) {
              if (!line.startsWith("data:")) continue;
              const jsonStr = line.slice("data:".length).trim();
              if (!jsonStr) continue;

              let parsed: ConciergeStreamEvent;
              try {
                parsed = JSON.parse(jsonStr) as ConciergeStreamEvent;
              } catch {
                const msg = "Failed to parse stream event JSON";
                events.emit({ type: "error", message: msg });
                done.reject(new Error(msg));
                return;
              }

              switch (parsed.type) {
                case "text":
                  events.emit(parsed);
                  text.emit(parsed.textDelta);
                  break;
                case "toolResult":
                  if (parsed.sources.length) events.emit({ type: "sources", sources: parsed.sources });
                  break;
                case "metadata":
                  events.emit(parsed);
                  break;
                case "done":
                  sawDone = true;
                  events.emit(parsed);
                  done.resolve({
                    threadId: parsed.threadId,
                    userId: parsed.userId,
                    text: parsed.text,
                    sources: parsed.sources,
                    metadata: parsed.metadata
                  });
                  shouldStop = true;
                  void reader.cancel().catch(() => undefined);
                  break;
                case "error":
                  events.emit(parsed);
                  done.reject(new Error(parsed.message));
                  return;
              }
            }
          }
        }

        if (!sawDone) done.reject(new Error("Stream ended without done event"));
      } catch (e) {
        const message = e instanceof Error ? e.message : String(e);
        events.emit({ type: "error", message });
        done.reject(e);
      } finally {
        events.end();
        text.end();
      }
    })();

    return {
      events: events.iterable,
      textStream: text.iterable,
      done: done.promise,
      cancel: () => {
        abortController.abort();
      }
    };
  };

  const generateText: ConciergeClient["generateText"] = async (input) => {
    const run = streamText(input);
    try {
      return await run.done;
    } finally {
      run.cancel();
    }
  };

  return { streamText, generateText };
}

