import { randomUid } from "../util/uid.js";

export interface StorageLike {
  getItem: (key: string) => string | null;
  setItem: (key: string, value: string) => void;
  removeItem: (key: string) => void;
}

export type PersistThreadMessages =
  | boolean
  | {
      storageKey?: string;
      maxMessagesPerThread?: number;
      storage?: StorageLike;
    };

export interface PersistThreadMessagesResolved {
  storageKey: string;
  maxMessagesPerThread: number;
  storage: StorageLike;
}

export type ThreadMessageRole = "user" | "assistant";

export interface ThreadMessage {
  id: string;
  role: ThreadMessageRole;
  text: string;
  ts: number;
}

interface PersistedStateV1 {
  v: 1;
  userId: string;
  currentThreadId: string | null;
  threadIds: string[];
  threads: Record<string, { messages: ThreadMessage[] }>;
}

const DEFAULT_STORAGE_KEY = "contentstack:agents-sdk:threadMessages";
const DEFAULT_MAX_MESSAGES = 200;

function resolveStorage(explicit?: StorageLike): StorageLike | null {
  if (explicit) return explicit;
  const g = globalThis as unknown as { localStorage?: StorageLike };
  const s = g.localStorage;
  if (!s) return null;
  if (typeof s.getItem !== "function") return null;
  if (typeof s.setItem !== "function") return null;
  if (typeof s.removeItem !== "function") return null;
  return s;
}

export function resolvePersistThreadMessages(persist?: PersistThreadMessages): PersistThreadMessagesResolved | null {
  if (!persist) return null;
  const opts = persist === true ? {} : persist;
  const storage = resolveStorage(opts.storage);
  if (!storage) return null;
  const storageKey = typeof opts.storageKey === "string" && opts.storageKey.trim() ? opts.storageKey.trim() : DEFAULT_STORAGE_KEY;
  const maxMessagesPerThread =
    typeof opts.maxMessagesPerThread === "number" && Number.isFinite(opts.maxMessagesPerThread) && opts.maxMessagesPerThread > 0
      ? Math.floor(opts.maxMessagesPerThread)
      : DEFAULT_MAX_MESSAGES;
  return { storageKey, maxMessagesPerThread, storage };
}

function safeParseState(raw: string): PersistedStateV1 | null {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw) as unknown;
  } catch {
    return null;
  }
  if (!parsed || typeof parsed !== "object") return null;
  const p = parsed as Partial<PersistedStateV1>;
  if (p.v !== 1) return null;
  if (typeof p.userId !== "string") return null;
  if (!(p.currentThreadId === null || typeof p.currentThreadId === "string")) return null;
  if (!Array.isArray(p.threadIds)) return null;
  if (!p.threads || typeof p.threads !== "object") return null;
  return p as PersistedStateV1;
}

function readState(r: PersistThreadMessagesResolved): PersistedStateV1 | null {
  try {
    const raw = r.storage.getItem(r.storageKey);
    if (!raw) return null;
    return safeParseState(raw);
  } catch {
    return null;
  }
}

function writeState(r: PersistThreadMessagesResolved, state: PersistedStateV1): void {
  try {
    r.storage.setItem(r.storageKey, JSON.stringify(state));
  } catch {
    void 0;
  }
}

function ensureState(r: PersistThreadMessagesResolved): PersistedStateV1 {
  const existing = readState(r);
  if (existing) return existing;
  const init: PersistedStateV1 = {
    v: 1,
    userId: randomUid(),
    currentThreadId: null,
    threadIds: [],
    threads: {}
  };
  writeState(r, init);
  return init;
}

export function getPersistedUserId(r: PersistThreadMessagesResolved): string {
  return ensureState(r).userId;
}

export function setPersistedUserId(r: PersistThreadMessagesResolved, userId: string): void {
  const nextId = userId.trim();
  if (!nextId) return;
  const state = ensureState(r);
  if (state.userId === nextId) return;
  const next: PersistedStateV1 = { ...state, userId: nextId };
  writeState(r, next);
}

export function getPersistedCurrentThreadId(r: PersistThreadMessagesResolved): string | null {
  return ensureState(r).currentThreadId;
}

export function setPersistedCurrentThreadId(r: PersistThreadMessagesResolved, threadId: string | null): void {
  const state = ensureState(r);
  const trimmed = threadId?.trim();
  const nextTid = trimmed === "" ? null : trimmed ?? null;
  if (state.currentThreadId === nextTid) return;
  const next: PersistedStateV1 = { ...state, currentThreadId: nextTid };
  writeState(r, next);
}

export function getPersistedThreadIds(r: PersistThreadMessagesResolved): string[] {
  return ensureState(r).threadIds;
}

export function addPersistedThreadId(r: PersistThreadMessagesResolved, threadId: string): void {
  const tid = threadId.trim();
  if (!tid) return;
  const state = ensureState(r);
  if (state.threadIds.includes(tid)) return;
  const next: PersistedStateV1 = { ...state, threadIds: [...state.threadIds, tid] };
  writeState(r, next);
}

export function clearPersistedAll(r: PersistThreadMessagesResolved): void {
  try {
    r.storage.removeItem(r.storageKey);
  } catch {
    void 0;
  }
}

export function clearPersistedThread(r: PersistThreadMessagesResolved, threadId: string): void {
  const tid = threadId.trim();
  if (!tid) return;
  const state = readState(r);
  if (!state) return;
  const rest = Object.fromEntries(Object.entries(state.threads).filter(([k]) => k !== tid));
  const nextThreadIds = state.threadIds.filter((t) => t !== tid);
  const nextCurrent = state.currentThreadId === tid ? null : state.currentThreadId;
  const next: PersistedStateV1 = { ...state, currentThreadId: nextCurrent, threadIds: nextThreadIds, threads: rest };
  writeState(r, next);
}

export function getThreadMessages(params: {
  threadId: string;
  storageKey?: string;
  storage?: StorageLike;
}): ThreadMessage[] {
  const persist: PersistThreadMessages = {
    maxMessagesPerThread: DEFAULT_MAX_MESSAGES,
    ...(typeof params.storageKey === "string" ? { storageKey: params.storageKey } : {}),
    ...(params.storage ? { storage: params.storage } : {})
  };
  const resolved = resolvePersistThreadMessages(persist);
  if (!resolved) return [];
  const tid = params.threadId.trim();
  if (!tid) return [];
  const state = readState(resolved);
  const msgs = state?.threads[tid]?.messages;
  return Array.isArray(msgs) ? msgs : [];
}

export function setThreadMessages(params: {
  threadId: string;
  messages: ThreadMessage[];
  storageKey?: string;
  storage?: StorageLike;
}): void {
  const persist: PersistThreadMessages = {
    maxMessagesPerThread: DEFAULT_MAX_MESSAGES,
    ...(typeof params.storageKey === "string" ? { storageKey: params.storageKey } : {}),
    ...(params.storage ? { storage: params.storage } : {})
  };
  const resolved = resolvePersistThreadMessages(persist);
  if (!resolved) return;
  const tid = params.threadId.trim();
  if (!tid) return;
  const state = ensureState(resolved);
  const nextMessages = Array.isArray(params.messages) ? params.messages.slice(-resolved.maxMessagesPerThread) : [];
  const nextThreads = { ...state.threads, [tid]: { messages: nextMessages } };
  const nextThreadIds = state.threadIds.includes(tid) ? state.threadIds : [...state.threadIds, tid];
  const next: PersistedStateV1 = { ...state, threadIds: nextThreadIds, threads: nextThreads };
  writeState(resolved, next);
}

function shouldSkipAppend(existing: ThreadMessage[], role: ThreadMessageRole, text: string): boolean {
  const last = existing[existing.length - 1];
  if (!last) return false;
  return last.role === role && last.text === text;
}

export function appendThreadMessage(
  r: PersistThreadMessagesResolved,
  threadId: string,
  message: { role: ThreadMessageRole; text: string; ts?: number; id?: string }
): void {
  const tid = threadId.trim();
  if (!tid) return;
  const txt = message.text.trim();
  if (!txt) return;
  const state = ensureState(r);
  const prev = state.threads[tid]?.messages ?? [];
  if (shouldSkipAppend(prev, message.role, txt)) return;
  const nextMsg: ThreadMessage = {
    id: message.id ?? randomUid(),
    role: message.role,
    text: txt,
    ts: typeof message.ts === "number" && Number.isFinite(message.ts) ? message.ts : Date.now()
  };
  const nextMessages = [...prev, nextMsg].slice(-r.maxMessagesPerThread);
  const nextThreads = { ...state.threads, [tid]: { messages: nextMessages } };
  const nextThreadIds = state.threadIds.includes(tid) ? state.threadIds : [...state.threadIds, tid];
  const next: PersistedStateV1 = {
    ...state,
    currentThreadId: state.currentThreadId ?? tid,
    threadIds: nextThreadIds,
    threads: nextThreads
  };
  writeState(r, next);
}

